CREATE TABLE `mensagens` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `agendamento_id` bigint DEFAULT NULL,
  `empresa_remetente_id` bigint NOT NULL,
  `empresa_destinatario_id` bigint NOT NULL,
  `conteudo` text NOT NULL,
  `lido` tinyint(1) DEFAULT '0',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `fk_mensagens_agendamento` (`agendamento_id`),
  KEY `fk_mensagens_remetente` (`empresa_remetente_id`),
  KEY `fk_mensagens_destinatario` (`empresa_destinatario_id`),
  CONSTRAINT `fk_mensagens_agendamento` FOREIGN KEY (`agendamento_id`) REFERENCES `agendamentos` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_mensagens_destinatario` FOREIGN KEY (`empresa_destinatario_id`) REFERENCES `empresas` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_mensagens_remetente` FOREIGN KEY (`empresa_remetente_id`) REFERENCES `empresas` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
