DROP TABLE IF EXISTS `postagens`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `postagens` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `empresa_id` bigint NOT NULL,
  `tipo_postagem` enum('OFERTA_RESIDUO','OFERTA_SERVICO') NOT NULL,
  `titulo` varchar(255) NOT NULL,
  `descricao` text,
  `tipo_residuo` varchar(500) DEFAULT NULL,
  `area_cobertura` varchar(150) DEFAULT NULL,
  `peso` decimal(10,2) DEFAULT '0.00',
  `capacidade_coleta` decimal(10,2) DEFAULT '0.00',
  `endereco` text,
  `foto_empresa` longtext,
  `foto_residuos` longtext,
  `status` enum('ABERTA','PAUSADA','ENCERRADA','CANCELADA') DEFAULT 'ABERTA',
  `status_moderacao` enum('PENDENTE','APROVADA','REJEITADA','BLOQUEADA') DEFAULT 'APROVADA',
  `motivo_moderacao` text,
  `moderado_em` datetime DEFAULT NULL,
  `moderado_por` varchar(255) DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `endereco_retirada` text,
  `max_peso_coleta` decimal(10,2) DEFAULT NULL,
  `dias_disponibilidade` text,
  `hora_fim` time DEFAULT NULL,
  `hora_inicio` time DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_postagens_empresa` (`empresa_id`),
  KEY `idx_postagens_tipo` (`tipo_postagem`),
  CONSTRAINT `fk_postagens_empresa` FOREIGN KEY (`empresa_id`) REFERENCES `empresas` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
